import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useFormik } from 'formik';
import { toast } from 'react-toastify';
import axiosInstance from '../utils/axiosInstance';
import { registerSchema } from '../schemas';

export default function Register() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState(null);

  const formik = useFormik({
    initialValues: { name: '', email: '', password: '', phone: '', address: '', govIdType: 'AADHAAR', govIdNumber: '', accountType: 'SAVINGS' },
    validationSchema: registerSchema,
    onSubmit: async (values) => {
      if (!file) return toast.error('Please upload your government ID document');
      setLoading(true);
      try {
        const fd = new FormData();
        Object.entries(values).forEach(([k, v]) => fd.append(k, v));
        fd.append('govIdDocument', file);
        await axiosInstance.post('/auth/register', fd, { headers: { 'Content-Type': 'multipart/form-data' } });
        toast.success('Registration submitted! Await KYC approval from admin.');
        navigate('/login');
      } catch (err) {
        toast.error(err.response?.data?.message || 'Registration failed');
      } finally { setLoading(false); }
    }
  });

  const inp = { padding: '9px 12px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, width: '100%', boxSizing: 'border-box' };
  const err = { color: '#ef4444', fontSize: 12, marginTop: 2 };
  const label = { fontSize: 13, fontWeight: 600, color: '#374151', display: 'block', marginBottom: 4 };

  const Field = ({ name, type = 'text', placeholder, as }) => (
    <div style={{ marginBottom: 14 }}>
      <label style={label}>{name.replace(/([A-Z])/g, ' $1').replace(/^./, s => s.toUpperCase())}</label>
      {as === 'select' ? (
        <select name={name} style={inp} {...formik.getFieldProps(name)}>
          {name === 'govIdType' && <><option value="AADHAAR">Aadhaar</option><option value="PAN">PAN</option></>}
          {name === 'accountType' && <><option value="SAVINGS">Savings Account</option><option value="CURRENT">Current Account</option></>}
        </select>
      ) : (
        <input name={name} type={type} style={inp} placeholder={placeholder} {...formik.getFieldProps(name)} />
      )}
      {formik.touched[name] && formik.errors[name] && <div style={err}>{formik.errors[name]}</div>}
    </div>
  );

  return (
    <div className="min-vh-100 d-flex align-items-center justify-content-center" style={{ background: '#f1f5f9', padding: '16px' }}>
      <div className="w-100" style={{ maxWidth: 520 }}>
        <div className="bg-white rounded-3 p-4 p-md-5" style={{ boxShadow: '0 4px 24px rgba(0,0,0,0.08)' }}>
          <h2 style={{ margin: '0 0 4px', color: '#1e293b' }}> Open Account</h2>
          <p style={{ color: '#64748b', margin: '0 0 24px', fontSize: 14 }}>Fill in your details. Admin will verify your KYC.</p>
          <form onSubmit={formik.handleSubmit}>
            {/* Full-width name row */}
            <Field name="name" placeholder="Full Name" />

            {/* Two-column responsive grid */}
            <div className="row g-0">
              <div className="col-12 col-md-6 pe-md-2"><Field name="email" type="email" placeholder="Email" /></div>
              <div className="col-12 col-md-6 ps-md-2"><Field name="password" type="password" placeholder="Password (min 8)" /></div>
              <div className="col-12 col-md-6 pe-md-2"><Field name="phone" placeholder="10-digit phone" /></div>
              <div className="col-12 col-md-6 ps-md-2"><Field name="address" placeholder="Your address" /></div>
              <div className="col-12 col-md-6 pe-md-2"><Field name="govIdType" as="select" /></div>
              <div className="col-12 col-md-6 ps-md-2"><Field name="govIdNumber" placeholder="ID number" /></div>
              <div className="col-12"><Field name="accountType" as="select" /></div>
            </div>

            <div style={{ marginBottom: 14 }}>
              <label style={label}>Upload Government ID Document</label>
              <input type="file" accept="image/*,.pdf" onChange={e => setFile(e.target.files[0])} style={inp} />
              {!file && <div style={err}>Document upload required</div>}
            </div>

            <button
              type="submit" disabled={loading}
              className="btn w-100"
              style={{ padding: 12, borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 700, fontSize: 15, marginTop: 8 }}
            >
              {loading ? 'Submitting...' : 'Submit Registration'}
            </button>
          </form>
          <p style={{ textAlign: 'center', marginTop: 16, fontSize: 13 }}>Already have an account? <Link to="/login" style={{ color: '#3b82f6' }}>Login</Link></p>
        </div>
      </div>
    </div>
  );
}
